const express = require('express');
const redis = require('redis');
const oauth2orize = require('oauth2orize');
const jwt = require('jsonwebtoken');

const app = express();
const server = oauth2orize.createServer();

// Set up Redis client
const redisClient = redis.createClient({ host: 'localhost', port: 6379 });
redisClient.on('error', (err) => {
  console.log(`Error connecting to Redis: ${err}`);
});

// Define the authorization code grant type
server.grant(oauth2orize.grant.code((client, redirectUri, user, ares, done) => {
  // Generate a refresh token with a long expiration (1 year)
  const refreshToken = jwt.sign({}, process.env.REFRESH_TOKEN_SECRET, {
    expiresIn: '365d',
  });

  // Store the refresh token in Redis with a long TTL
  redisClient.set(refreshToken, JSON.stringify({ clientId: client.id }), 'EX', 31536000);

  // Return the authorization code and refresh token to the client
  done(null, ares.code, { refresh_token: refreshToken });
}));

// Define the token endpoint
server.token()((req, res) => {
  const { grant_type, refresh_token } = req.body;

  // Validate the request
  if (grant_type !== 'refresh_token') {
    return res.status(400).json({ error: 'invalid_request' });
  }

  // Validate the refresh token
  redisClient.get(refreshToken, (err, result) => {
    if (err || !result) {
      return res.status(401).json({ error: 'invalid_grant' });
    }

    // Generate a new access token and refresh token with a long expiration (1 year)
    const accessToken = jwt.sign({}, process.env.ACCESS_TOKEN_SECRET, {
      expiresIn: '365d',
    });
    const newRefreshToken = jwt.sign({}, process.env.REFRESH_TOKEN_SECRET, {
      expiresIn: '365d',
    });

    // Store the new refresh token in Redis with a long TTL
    redisClient.set(newRefreshToken, JSON.stringify({ clientId: result.clientId }), 'EX', 31536000);

    // Return the access token and refresh token to the client
    res.json({ access_token: accessToken, refresh_token: newRefreshToken });
  });
});

// Start the server
app.listen(3000, () => {
  console.log('Server started on port 3000');
});